DROP TABLE IF EXISTS settings;
DROP TABLE IF EXISTS wilayah;
DROP TABLE IF EXISTS demografi;
DROP TABLE IF EXISTS usia;
DROP TABLE IF EXISTS aparatur;
DROP TABLE IF EXISTS layanan;
DROP TABLE IF EXISTS galeri;
DROP TABLE IF EXISTS berita;
DROP TABLE IF EXISTS acara;
DROP TABLE IF EXISTS kontak;
DROP TABLE IF EXISTS ui;
DROP TABLE IF EXISTS kepala_dukuh;
CREATE TABLE settings (id INT PRIMARY KEY, nama VARCHAR(255), deskripsi TEXT, visi TEXT, sejarah TEXT, header_bg TEXT, logo TEXT, map_embed TEXT) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE wilayah (dusun INT, rw INT, rt INT, luas VARCHAR(100), alamat_kantor TEXT) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE demografi (jumlah_penduduk INT, laki INT, perempuan INT) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE usia (kategori VARCHAR(100) PRIMARY KEY, jumlah INT) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE aparatur (id INT AUTO_INCREMENT PRIMARY KEY, jabatan VARCHAR(150), nama VARCHAR(150), kontak VARCHAR(100)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE layanan (id INT AUTO_INCREMENT PRIMARY KEY, nama VARCHAR(200), deskripsi TEXT, lokasi VARCHAR(200)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE galeri (id INT AUTO_INCREMENT PRIMARY KEY, url TEXT, caption TEXT) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE berita (id INT AUTO_INCREMENT PRIMARY KEY, judul VARCHAR(200), tanggal DATE, isi TEXT) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE acara (id INT AUTO_INCREMENT PRIMARY KEY, judul VARCHAR(200), tanggal DATE, lokasi VARCHAR(200), img TEXT) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE kontak (email VARCHAR(200), telp VARCHAR(50)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE ui (key VARCHAR(50) PRIMARY KEY, value TINYINT(1)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE kepala_dukuh (nama VARCHAR(200), jabatan VARCHAR(150), foto TEXT, sambutan TEXT) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
INSERT INTO settings (id,nama,deskripsi,visi,sejarah,header_bg,logo,map_embed) VALUES (1,'Banaran Lor','Portal informasi resmi Padukuhan Banaran Lor sebagai rujukan data, layanan, dan kegiatan warga.','Terwujudnya padukuhan yang mandiri, sehat, cerdas, dan sejahtera.','Padukuhan Sembada berdiri sejak awal abad ke-20 sebagai permukiman pertanian. Perkembangan pesat terjadi setelah dibangun balai padukuhan dan sarana jalan, sehingga aktivitas sosial dan ekonomi semakin meningkat.','https://picsum.photos/id/1043/1200/300','https://picsum.photos/seed/banaranlor-logo/80/80','https://www.google.com/maps?q=Banaran%20Lor%2C%20Banguncipto%2C%20Sentolo%2C%20Kulon%20Progo&output=embed');
